import { getChannelInfo } from "../services/youtube.service.js";
import { ApiError } from "../utils/ApiError.js";

export const fetchChannel = async (req, res, next) => {
  try {
    // Pass the token generated by youtubeToken.middleware.js directly to the service
    const data = await getChannelInfo(req.ytToken);

    res.status(200).json({
      success: true,
      data,
    });
  } catch (error) {
    // Pass errors correctly to the global error middleware handler
    next(new ApiError(500, "Failed to fetch YouTube Channel Data", [], error.stack));
  }
};
